                    self.write_operand(
                        &op.op1,
                        new_val.clone(),
                        &mut cvs,
                        &mut tmps,
                        &static_cv_keys,
                    );
                    self.write_operand(&op.result, new_val, &mut cvs, &mut tmps, &static_cv_keys);
